module RefModule(A, B, result);input [3:0] A;
    input [3:0] B;
    output reg [7:0] result; // changed to reg to hold the value in always block

    reg [7:0] final_sig;
    reg [3:0] i;

    always @* begin
        final_sig = 0;
        for (i = 0; i < 4; i = i+1) begin
            if (B[i] == 1) begin
                final_sig = final_sig + (A << i);
            end
        end
        result = final_sig; // result can now be assigned
    end
endmodule
